  1→// Common types shared across the subtitle pipeline
  2→
  3→// Configuration options
  4→export interface Config {
  5→  videoPath: string;
  6→  srtPath?: string; // Optional reference SRT
  7→  outputDir: string;
  8→  intermediateDir: string;
  9→  sourceLanguages?: string[]; // Optional: Languages spoken in the source video (e.g., ['ml', 'ta'])
 10→  targetLanguages: string[]; // e.g., ['korean', 'japanese'
 11→  translationPromptTemplatePath?: string; // Path to the translation prompt template file
 12→  transcriptionModel: string;
 13→  translationModel: string;
 14→  chunkDuration: number; // seconds
 15→  chunkOverlap: number; // seconds
 16→  chunkFormat: "mp3" | "mp4";
 17→  maxConcurrent: number;
 18→  retries: number; // General retries (e.g., for translation API calls)
 19→  transcriptionRetries: number; // Specific retries for transcription validation failure
 20→  force: boolean;
 21→  apiKeys: {
 22→    gemini?: string;
 23→    anthropic?: string;
 24→  };
 25→  processOnlyPart?: number; // Optional: Process only this specific part number
 26→  disableTimingValidation?: boolean; // Optional: Disable timing checks in validator
 27→  useResponseTimings?: boolean; // Use timings from LLM response instead of original SRT
 28→  markFallbacks?: boolean; // Add marker to subtitles using original text
 29→  subtitleColorEnglish?: string; // Color for English text
 30→  subtitleColorTarget?: string; // Color for the target language text
 31→  outputOffsetSeconds?: number; // Optional: Add seconds offset to final output timings
 32→  inputOffsetSeconds?: number; // Optional: Add seconds offset to the input original SRT timings
 33→}
 34→
 35→// Information about each processed chunk
 36→export interface ChunkInfo {
 37→  partNumber: number;
 38→  startTimeSeconds: number;
 39→  endTimeSeconds: number;
 40→  // File paths within intermediateDir
 41→  mediaChunkPath?: string; // Path to mp3 or mp4 chunk
 42→  srtChunkPath?: string; // Path to reference SRT chunk
 43→  rawTranscriptPath?: string;
 44→  adjustedTranscriptPath?: string; // Path to transcript with absolute timestamps
 45→  responsePath?: string; // Path to the RAW LLM text response file
 46→  llmRequestLogPath?: string; // Path to structured JSON log of the request sent to LLM
 47→  llmResponseLogPath?: string; // Path to structured JSON log of the full LLM response object
 48→  llmTranscriptionInputTokens?: number; // Tokens for transcription step (most recent attempt)
 49→  llmTranscriptionOutputTokens?: number;
 50→  llmTranslationInputTokens?: number; // Tokens for translation step (most recent attempt)
 51→  llmTranslationOutputTokens?: number;
 52→  cost?: number; // Cost of API calls for this chunk (most recent attempt)
 53→
 54→  // Track all attempts
 55→  allTranscriptionAttempts?: {
 56→    inputTokens: number;
 57→    outputTokens: number;
 58→    cost: number;
 59→  }[];
 60→  allTranslationAttempts?: {
 61→    inputTokens: number;
 62→    outputTokens: number;
 63→    cost: number;
 64→  }[];
 65→  totalTranscriptionCost?: number; // Sum of all transcription attempt costs
 66→  totalTranslationCost?: number; // Sum of all translation attempt costs
 67→  totalCost?: number; // Sum of all costs for this chunk
 68→  parsedDataPath?: string; // Path to parsed JSON from response
 69→  failedTranscriptPath?: string; // Path to raw transcript if it failed validation
 70→  status:
 71→    | "pending"
 72→    | "splitting"
 73→    | "transcribing"
 74→    | "prompting" // Status indicating ready for translation prompt generation + call
 75→    | "translating" // In progress of calling translation LLM
 76→    | "parsing" // Raw response received, ready for parsing
 77→    | "validating"
 78→    | "completed"
 79→    | "failed";
 80→  error?: string; // Store error message if failed
 81→}
 82→
 83→// Parsed entry from reference SRT
 84→export interface SrtEntry {
 85→  id: number;
 86→  timingString: string;
 87→  startTimeSeconds: number;
 88→  endTimeSeconds: number;
 89→  text: string;
 90→}
 91→
 92→// Parsed entry from LLM translation response (REFINED)
 93→export interface ParsedTranslationEntry {
 94→  originalId: string; // Corresponds to SrtEntry ID, from <original_number>
 95→  originalLine?: string; // Text from <original_line>
 96→  originalTiming?: string; // Raw timing string from <original_timing>
 97→  parsedStartTimeSeconds?: number; // Parsed start time (if timing exists and is valid)
 98→  parsedEndTimeSeconds?: number; // Parsed end time (if timing exists and is valid)
 99→  translations: Record<string, string | null>; // { 'english': '...', 'korean': '...' } - Allow null if tag exists but is empty
100→  sourceChunk: number; // Which part number this came from
101→  sourceFormat: "markdown" | "direct_tag" | "regex" | "unknown"; // How the subline block was found
102→}
103→
104→// Define possible issue types
105→export type ParsingIssueType =
106→  | "MissingTag"
107→  | "InvalidTimingFormat"
108→  | "InvalidTimingValue"
109→  | "MalformedTag"
110→  | "AmbiguousStructure"
111→  | "ExtractionFailed"
112→  | "DuplicateId"
113→  | "NumberNotFound"
114→  | "TextNotFound"
115→  | "MarkdownBlockEmptyOrInvalid";
116→
117→// Issue found during processing (ensure ParseError is listed and lineNumber exists)
118→export interface ProcessingIssue {
119→  type:
120→    | ParsingIssueType
121→    | "SplitError"
122→    | "TranscriptionError"
123→    | "TimestampAdjustError"
124→    | "PromptGenError"
125→    | "TranslationError"
126→    | "ValidationError"
127→    | "MergeError"
128→    | "FormatError";
129→  severity: "error" | "warning" | "info";
130→  message: string;
131→  chunkPart?: number;
132→  subtitleId?: string | number; // ID from <original_number> if available
133→  context?: string; // Snippet or relevant data
134→  lineNumber?: number; // Optional line number from parser
135→}
136→
137→// Entry for the final, merged SRT file before formatting
138→export interface FinalSubtitleEntry {
139→  originalId: string; // Keep original ID for reference/debugging
140→  finalId: number; // Sequential ID for final output
141→  startTimeSeconds: number;
142→  endTimeSeconds: number;
143→  translations: Record<string, string | null>; // { 'english': 'Hello', 'korean': '안녕하세요' }
144→  isFallback?: boolean; // Did we use original SRT text?
145→  markFallback?: boolean; // Should this fallback be marked in output?
146→  timingSource: "original" | "llm"; // Where did the timing come from?
147→}
148→
149→/** Structure for cost breakdown */
150→export interface CostBreakdown {
151→  totalCost: number;
152→  transcriptionCost: number;
153→  translationCost: number;
154→  costPerModel: Record<string, number>; // e.g., { 'claude-3-5-sonnet': 1.23, 'gemini-1.5-flash': 0.45 }
155→  costPerMinute?: number; // Total cost / video duration in minutes
156→  warnings: string[]; // e.g., "Token count unavailable for transcription model X"
157→}
158→
159→/** Structure for the final report */
160→export interface PipelineReport {
161→  startTime: string;
162→  endTime: string;
163→  totalDurationSeconds: number;
164→  videoDurationSeconds?: number; // Add original video duration
165→  configUsed: Config;
166→  overallStatus: "Success" | "SuccessWithIssues" | "Failed";
167→  summary: {
168→    chunksTotal: number;
169→    chunksCompleted: number;
170→    chunksFailed: number;
171→    // Add token/cost summary?
172→  };
173→  issues: ProcessingIssue[];
174→  cost?: CostBreakdown; // Ensure this uses the exported type
175→  outputFilePath?: string;
176→  reportFilePath: string;
177→}
