 71→/** Type definition for the result of calculateChunks */
 72→export interface TimeChunk {
 73→  startTimeSeconds: number;
 74→  endTimeSeconds: number;
 75→  partNumber: number;
 76→}
 77→
 78→/**
 79→ * Calculate chunk time ranges based on total duration, chunk size, and overlap
 80→ * @param totalDurationSeconds Total duration of the media in seconds
 81→ * @param chunkDurationSeconds Duration of each chunk in seconds
 82→ * @param overlapSeconds Overlap between chunks in seconds
 83→ * @returns Array of TimeChunk objects
 84→ */
 85→export function calculateChunks(
 86→  totalDurationSeconds: number,
 87→  chunkDurationSeconds: number,
 88→  overlapSeconds: number
 89→): TimeChunk[] {
 90→  const chunks: TimeChunk[] = [];
 91→  let startTime = 0;
 92→  let partNumber = 1;
 93→
 94→  while (startTime < totalDurationSeconds) {
 95→    let endTime = Math.min(
 96→      startTime + chunkDurationSeconds,
 97→      totalDurationSeconds
 98→    );
 99→
100→    // If this is the last chunk and it's too short, merge with previous chunk
101→    if (
102→      endTime === totalDurationSeconds &&
103→      endTime - startTime < chunkDurationSeconds / 3
104→    ) {
105→      if (chunks.length > 0) {
106→        // Update the end time of the last chunk to include this small remainder
107→        chunks[chunks.length - 1].endTimeSeconds = endTime;
108→        break;
109→      }
110→    }
111→
112→    chunks.push({
113→      startTimeSeconds: startTime,
114→      endTimeSeconds: endTime,
115→      partNumber,
116→    });
117→
118→    // Move to next chunk with overlap
119→    startTime = endTime - overlapSeconds;
120→    partNumber++;
121→  }
122→
123→  return chunks;
124→}
