 13→/**
 14→ * Get the duration of a video file using ffprobe
 15→ * @param videoPath Path to the video file
 16→ * @returns Promise resolving to duration in seconds, or null if error
 17→ */
 18→export async function getVideoDuration(
 19→  videoPath: string
 20→): Promise<number | null> {
 21→  return new Promise((resolve) => {
 22→    const args = [
 23→      "-v",
 24→      "error",
 25→      "-show_entries",
 26→      "format=duration",
 27→      "-of",
 28→      "default=noprint_wrappers=1:nokey=1",
 29→      videoPath,
 30→    ];
 31→
 32→    logger.debug(`Running ffprobe to get duration of ${videoPath}`);
 33→    const ffprobe = spawn("ffprobe", args);
 34→    let output = "";
 35→    let errorOutput = "";
 36→
 37→    ffprobe.stdout.on("data", (data) => {
 38→      output += data.toString();
 39→    });
 40→
 41→    ffprobe.stderr.on("data", (data) => {
 42→      errorOutput += data.toString();
 43→    });
 44→
 45→    ffprobe.on("close", (code) => {
 46→      if (code !== 0) {
 47→        logger.error(`ffprobe exited with code ${code}: ${errorOutput}`);
 48→        resolve(null);
 49→        return;
 50→      }
 51→
 52→      const duration = parseFloat(output.trim());
 53→      if (isNaN(duration)) {
 54→        logger.error(`Could not parse duration from ffprobe output: ${output}`);
 55→        resolve(null);
 56→        return;
 57→      }
 58→
 59→      logger.debug(`Video duration: ${duration} seconds`);
 60→      resolve(duration);
 61→    });
 62→  });
 63→}
