235→
236→    const { chunks, issues } = await split(options);
237→
238→    // Log issues
239→    if (issues.length > 0) {
240→      warn(`Encountered ${issues.length} issues:`);
241→      issues.forEach((issue) => {
242→        const prefix =
243→          issue.severity === "error"
244→            ? chalk.red("ERROR")
245→            : chalk.yellow("WARNING");
246→        console.log(`${prefix}: ${issue.message}`);
