  1→import { join, basename } from "path";
  2→import { readFile, writeFile } from "fs/promises";
  3→import { existsSync } from "fs";
  4→import type { ChunkInfo, ProcessingIssue, SrtEntry } from "../types.js";
  5→import { parseSrtTiming, formatSrtTiming } from "../utils/time_utils.js";
  6→import { ensureDir } from "../utils/file_utils.js";
  7→import * as logger from "../utils/logger.js";
  8→import { parseSrtFile } from "../utils/srt_utils.js";
  9→
 10→/**
 11→ * Filter SRT entries for a specific chunk based on time range
 12→ * @param entries All SRT entries
 13→ * @param startTime Chunk start time in seconds
 14→ * @param endTime Chunk end time in seconds
 15→ * @param expandRange Whether to include subtitles partially overlapping with the range
 16→ * @returns Filtered entries
 17→ */
 18→export function filterEntriesForChunk(
 19→  entries: SrtEntry[],
 20→  startTime: number,
 21→  endTime: number,
 22→  expandRange: boolean = true
 23→): SrtEntry[] {
 24→  return entries.filter((entry) => {
 25→    // Fully contained entries
 26→    if (
 27→      entry.startTimeSeconds >= startTime &&
 28→      entry.endTimeSeconds <= endTime
 29→    ) {
 30→      return true;
 31→    }
 32→
 33→    // Partially overlapping entries (if requested)
 34→    if (expandRange) {
 35→      // Entry starts before chunk but ends within chunk
 36→      if (
 37→        entry.startTimeSeconds < startTime &&
 38→        entry.endTimeSeconds > startTime
 39→      ) {
 40→        return true;
 41→      }
 42→
 43→      // Entry starts within chunk but ends after chunk
 44→      if (entry.startTimeSeconds < endTime && entry.endTimeSeconds > endTime) {
 45→        return true;
 46→      }
 47→    }
 48→
 49→    return false;
 50→  });
 51→}
 52→
 53→/**
 54→ * Write filtered entries to an SRT file for a chunk, optionally skipping if exists.
 55→ * @param entries SRT entries to write
 56→ * @param outputPath Output file path
 57→ * @param force Whether to force writing even if file exists
 58→ * @returns Promise resolving to true if successful
 59→ */
 60→export async function writeChunkSrt(
 61→  entries: SrtEntry[],
 62→  outputPath: string,
 63→  force: boolean
 64→): Promise<boolean> {
 65→  // Skip if file exists and not forcing
 66→  if (!force && existsSync(outputPath)) {
 67→    logger.debug(
 68→      `SRT chunk ${basename(outputPath)} already exists. Skipping write.`
 69→    );
 70→    return true; // Treat as success if skipped
 71→  }
 72→
 73→  try {
 74→    // Format the entries as SRT content
 75→    let content = "";
 76→    for (const entry of entries) {
 77→      content += `${entry.id}\n`;
 78→      content += `${entry.timingString}\n`;
 79→      content += `${entry.text}\n\n`;
 80→    }
 81→
 82→    await writeFile(outputPath, content, "utf-8");
 83→    logger.debug(`Wrote ${entries.length} subtitles to ${outputPath}`);
 84→    return true;
 85→  } catch (error) {
 86→    logger.error(`Failed to write chunk SRT: ${error}`);
 87→    return false;
 88→  }
 89→}
 90→
 91→/**
 92→ * Split an SRT file into chunks based on time ranges
 93→ * @param srtPath Path to the SRT file
 94→ * @param chunks Chunk info objects with time ranges
 95→ * @param outputDir Directory to save chunk SRTs
 96→ * @param force Whether to force writing even if file exists
 97→ * @param inputOffsetSeconds Input offset in seconds
 98→ * @returns Promise resolving to updated chunks and issues
 99→ */
100→export async function splitSrt(
101→  srtPath: string,
102→  chunks: ChunkInfo[],
103→  outputDir: string,
104→  force: boolean,
105→  inputOffsetSeconds: number = 0
106→): Promise<{ chunks: ChunkInfo[]; issues: ProcessingIssue[] }> {
107→  const issues: ProcessingIssue[] = [];
108→
109→  // Parse the SRT file, applying the offset
110→  const entries = await parseSrtFile(srtPath, inputOffsetSeconds);
111→  if (!entries) {
112→    const issue: ProcessingIssue = {
113→      type: "SplitError",
114→      severity: "error",
115→      message: `Failed to parse SRT file: ${srtPath}`,
116→    };
117→    issues.push(issue);
118→    return { chunks, issues };
119→  }
120→
121→  // Create output directory
122→  if (!ensureDir(outputDir)) {
123→    const issue: ProcessingIssue = {
124→      type: "SplitError",
125→      severity: "error",
126→      message: `Failed to create output directory for SRT chunks: ${outputDir}`,
127→    };
128→    issues.push(issue);
129→    return { chunks, issues };
130→  }
131→
132→  logger.info(
133→    `Splitting SRT file into ${chunks.length} chunks (Force: ${force}, Input Offset: ${inputOffsetSeconds}s)`
134→  );
135→
136→  // Process each chunk
137→  for (const chunk of chunks) {
138→    // Skip failed chunks
139→    if (chunk.status === "failed") {
140→      continue;
141→    }
142→
143→    // Filter entries for this chunk
144→    const chunkEntries = filterEntriesForChunk(
145→      entries,
146→      chunk.startTimeSeconds,
147→      chunk.endTimeSeconds
148→    );
149→
150→    if (chunkEntries.length === 0) {
151→      logger.warn(
152→        `No subtitles found for chunk ${chunk.partNumber} (${chunk.startTimeSeconds}s - ${chunk.endTimeSeconds}s)`
153→      );
154→    }
155→
156→    // Generate output path
157→    const srtChunkPath = join(
158→      outputDir,
159→      `part${chunk.partNumber.toString().padStart(2, "0")}.srt`
160→    );
161→    chunk.srtChunkPath = srtChunkPath;
162→
163→    // Pass force flag to write function
164→    const success = await writeChunkSrt(chunkEntries, srtChunkPath, force);
165→    if (!success) {
166→      issues.push({
167→        type: "SplitError",
168→        severity: "warning",
169→        message: `Failed to write SRT chunk for part ${chunk.partNumber}`,
170→        chunkPart: chunk.partNumber,
171→      });
172→    }
173→  }
174→
175→  logger.info(`SRT splitting complete`);
176→  return { chunks, issues };
177→}
