311→async function cliMain() {
312→  const program = new Command();
313→
314→  program
315→    .name("subtitle-transcriber")
316→    .description("Transcribe media chunks using Gemini API")
317→    .requiredOption(
318→      "-i, --input <path>",
319→      "Path to chunk_info.json file generated by the splitter"
320→    )
321→    .requiredOption(
322→      "-d, --intermediate-dir <path>",
323→      "Path to the intermediate directory (used for transcript output)"
324→    )
325→    .option(
326→      "-m, --model <name>",
327→      "Gemini model for transcription (overrides config)"
328→    )
329→    .option("-k, --api-key <key>", "Gemini API Key (overrides env)")
330→    .option(
331→      "-c, --concurrent <number>",
332→      "Max concurrent transcriptions (overrides config)"
333→    )
334→    .option("-r, --retries <number>", "Max validation retries per chunk", "1") // Add retry option
335→    .option("--log-file <path>", "Path to log file")
336→    .option(
337→      "--log-level <level>",
338→      "Log level (debug, info, warn, error)",
339→      "info"
340→    )
341→    .option("-P, --part <number>", "Process only a specific part number") // Add CLI option
342→    .parse(process.argv);
343→
344→  const opts = program.opts();
345→
346→  // Configure logger
347→  logger.configureLogger({
348→    logToFile: !!opts.logFile,
349→    logFilePath: opts.logFile,
350→    consoleLogLevel: opts.logLevel || "info", // Use consoleLogLevel
351→  });
352→
353→  const cliOptions: TranscriberCliOptions = {
354→    chunkInfoPath: opts.input,
355→    intermediateDir: opts.intermediateDir,
356→    transcriptionModel: opts.model,
357→    geminiApiKey: opts.apiKey,
358→    maxConcurrent: opts.concurrent ? parseInt(opts.concurrent) : undefined,
359→    transcriptionRetries: opts.retries ? parseInt(opts.retries) : undefined, // Parse retry option
360→    processOnlyPart: opts.part ? parseInt(opts.part) : undefined, // Parse CLI option
361→  };
362→
363→  try {
364→    logger.info(chalk.blueBright("--- Starting Transcription ---"));
365→
366→    // Load chunks
367→    const chunks = await readJsonFromFile<ChunkInfo[]>(
368→      cliOptions.chunkInfoPath
369→    );
370→    if (!chunks) {
371→      logger.error(
372→        `Failed to load chunk info from ${cliOptions.chunkInfoPath}`
373→      );
374→      process.exit(1);
375→    }
376→    logger.info(
377→      `Loaded info for ${chunks.length} chunks from ${cliOptions.chunkInfoPath}`
378→    );
379→
380→    // Build config
381→    const config: Partial<Config> = {
382→      intermediateDir: cliOptions.intermediateDir,
383→      transcriptionModel:
384→        cliOptions.transcriptionModel || "gemini-1.5-flash-latest",
385→      maxConcurrent:
386→        cliOptions.maxConcurrent !== undefined ? cliOptions.maxConcurrent : 5,
387→      transcriptionRetries:
388→        cliOptions.transcriptionRetries !== undefined
389→          ? cliOptions.transcriptionRetries
390→          : 1, // Use CLI value or default
391→      apiKeys: {
392→        gemini: cliOptions.geminiApiKey || process.env.GEMINI_API_KEY,
393→      },
394→      processOnlyPart: cliOptions.processOnlyPart, // Pass option to config
395→    };
396→
397→    // Check API key before proceeding
398→    if (!config.apiKeys?.gemini) {
399→      logger.error(
400→        "Gemini API key not found. Provide via --api-key or GEMINI_API_KEY env var."
401→      );
402→      process.exit(1);
403→    }
404→
405→    // Run the transcription process
406→    // Note: Progress bar is handled *inside* the transcribe function
407→    const { chunks: updatedChunks, issues } = await transcribe(
408→      chunks,
409→      config as Config
410→    );
411→
412→    // --- Final Reporting ---
413→    logger.info(chalk.blueBright("--- Transcription Report ---"));
414→
415→    const successCount = updatedChunks.filter(
416→      (c) => c.status === "prompting"
417→    ).length;
418→    const failCount = updatedChunks.filter(
419→      (c) => c.status === "failed" && c.error?.includes("Transcription")
420→    ).length; // Count specific transcription failures
421→    const skippedCount = chunks.length - successCount - failCount;
422→
423→    let reportContent = "";
424→    reportContent += `${chalk.green("Successful:")} ${successCount}
425→`;
426→    reportContent += `${chalk.red("Failed:")}    ${failCount}
427→`;
428→    if (skippedCount > 0) {
429→      reportContent += `${chalk.yellow(
430→        "Skipped:"
431→      )}   ${skippedCount} (Already processed or missing media)
432→`;
433→    }
434→
435→    if (issues.length > 0) {
436→      reportContent += `\n${chalk.yellowBright("Issues Encountered:")} (${
437→        issues.length
438→      })\n`;
439→      issues.forEach((issue) => {
440→        const prefix =
441→          issue.severity === "error"
442→            ? chalk.red("ERROR")
443→            : issue.severity === "warning"
444→            ? chalk.yellow("WARN")
445→            : chalk.blue("INFO");
446→        reportContent += `- ${prefix}: [Chunk ${issue.chunkPart || "N/A"}] ${
447→          issue.message
448→        }\n`;
449→        if (
450→          issue.severity === "error" &&
451→          issue.context &&
452→          opts.logLevel === "debug"
453→        ) {
454→          reportContent += `  ${chalk.gray(issue.context.split("\n")[0])}\n`; // Show first line of context in debug
455→        }
456→      });
457→    }
458→
459→    console.log(
460→      boxen(reportContent, {
461→        title: "Transcription Summary",
462→        padding: 1,
463→        margin: 1,
464→        borderStyle: "round",
465→        borderColor: "cyan",
466→      })
467→    );
468→
469→    // Save the updated chunk info
470→    const saveSuccess = await writeToFile(
471→      cliOptions.chunkInfoPath,
472→      updatedChunks
473→    );
474→    if (saveSuccess) {
475→      logger.success(
476→        `Updated chunk info saved to: ${cliOptions.chunkInfoPath}`
477→      );
478→    } else {
479→      logger.error(
480→        `Failed to save updated chunk info to: ${cliOptions.chunkInfoPath}`
481→      );
482→    }
483→
484→    process.exit(issues.some((i) => i.severity === "error") ? 1 : 0);
485→  } catch (err: any) {
486→    logger.error(`Fatal transcriber error: ${err.message || err}`, err.stack);
487→    console.error(
488→      boxen(chalk.red(`Fatal Error: ${err.message || err}`), {
489→        padding: 1,
490→        margin: 1,
491→        borderColor: "red",
492→      })
493→    );
494→    process.exit(1);
495→  }
496→}
