 26→/**
 27→ * Attempts to transcribe a chunk, validates the result, and retries if necessary.
 28→ */
 29→export async function transcribeChunk(
 30→  chunk: ChunkInfo,
 31→  config: Config,
 32→  retriesRemaining?: number
 33→): Promise<{ transcript: string | null; issues: ProcessingIssue[] }> {
 34→  const issues: ProcessingIssue[] = [];
 35→  const effectiveRetries = retriesRemaining ?? config.transcriptionRetries ?? 1;
 36→
 37→  const apiKey = config.apiKeys.gemini;
 38→  if (!apiKey) {
 39→    issues.push({
 40→      type: "TranscriptionError",
 41→      severity: "error",
 42→      message: "Missing Gemini API key for transcription.",
 43→      chunkPart: chunk.partNumber,
 44→    });
 45→    return { transcript: null, issues };
 46→  }
 47→
 48→  if (!chunk.mediaChunkPath || !existsSync(chunk.mediaChunkPath)) {
 49→    issues.push({
 50→      type: "TranscriptionError",
 51→      severity: "error",
 52→      message: `Media chunk file not found: ${chunk.mediaChunkPath}`,
 53→      chunkPart: chunk.partNumber,
 54→    });
 55→    return { transcript: null, issues };
 56→  }
 57→
 58→  const ai = new GoogleGenAI({ apiKey });
 59→  let uploadedFile;
 60→  // Define path to the *raw* transcript directory
 61→  const rawTranscriptDir = join(config.intermediateDir, "raw_llm_transcripts");
 62→
 63→  try {
 64→    logger.debug(
 65→      `[Chunk ${chunk.partNumber}] Uploading ${chunk.mediaChunkPath} (Attempt ${
 66→        (config.transcriptionRetries ?? 1) - effectiveRetries + 1
 67→      })...`
 68→    );
 69→    uploadedFile = await ai.files.upload({ file: chunk.mediaChunkPath });
 70→    logger.debug(
 71→      `[Chunk ${chunk.partNumber}] Uploaded ${basename(
 72→        chunk.mediaChunkPath
 73→      )} as ${uploadedFile.uri}`
 74→    );
 75→
 76→    const modelName = config.transcriptionModel;
 77→    const modelConfig = {
 78→      responseMimeType: "text/plain",
 79→    };
 80→
 81→    // Generate language part of the prompt
 82→    const languageInstruction = getLanguagePromptString(config.sourceLanguages);
 83→
 84→    const contents = [
 85→      {
 86→        role: "user",
 87→        parts: [
 88→          {
 89→            fileData: {
 90→              fileUri: uploadedFile.uri,
 91→              mimeType: uploadedFile.mimeType,
 92→            },
 93→          },
 94→          {
 95→            text: `Here's part of a movie I want to subtitle. Can you give me the transcript ${languageInstruction} to the best of your ability with timestamps? Don't worry about getting the timestamps correct - but transcribe all that you can. Don't think too much - just start - it's about 20 minutes.
 96→
 97→Use this format:
 98→relative (mm:ss - mm:ss) - (line)`,
 99→          },
100→        ],
101→      },
102→    ];
103→
104→    logger.debug(
105→      `[Chunk ${chunk.partNumber}] Transcribing using ${modelName} (Attempt ${
106→        (config.transcriptionRetries ?? 1) - effectiveRetries + 1
107→      })...`
108→    );
109→    let fullTranscript = "";
110→    const response = await ai.models.generateContentStream({
111→      model: modelName,
112→      config: modelConfig,
113→      contents,
114→    });
115→
116→    for await (const responseChunk of response) {
117→      fullTranscript += responseChunk.text;
118→    }
119→
120→    logger.debug(
121→      `[Chunk ${chunk.partNumber}] Finished transcription stream. Length: ${fullTranscript.length}`
122→    );
123→
124→    const validationResult = await validateTranscriptTimestamps(
125→      fullTranscript,
126→      chunk.srtChunkPath,
127→      config,
128→      MIN_TRANSCRIPT_LINES
129→    );
130→
131→    if (!validationResult.isValid) {
132→      logger.warn(
133→        `[Chunk ${chunk.partNumber}] Initial transcription failed validation: ${validationResult.message}`
134→      );
135→      const contextMessage = validationResult.referenceSrtSpanSeconds
136→        ? ` (LLM Span: ${validationResult.detectedLlmSpanSeconds?.toFixed(
137→            1
138→          )}s, Ref SRT Span: ${validationResult.referenceSrtSpanSeconds?.toFixed(
139→            1
140→          )}s)`
141→        : ` (LLM Span: ${validationResult.detectedLlmSpanSeconds?.toFixed(
142→            1
143→          )}s)`;
144→      issues.push({
145→        type: "TranscriptionError",
146→        severity: "warning",
147→        message: `Validation failed: ${validationResult.message}${contextMessage}`,
148→        chunkPart: chunk.partNumber,
149→      });
150→
151→      try {
152→        const failedTranscriptFile = `part${chunk.partNumber
153→          .toString()
154→          .padStart(2, "0")}_raw_transcript_FAILED.txt`;
155→        // Use the raw transcript directory path
156→        const failedPath = join(rawTranscriptDir, failedTranscriptFile);
157→        await writeToFile(
158→          failedPath,
159→          `--- VALIDATION FAILED ---\nReason: ${
160→            validationResult.message
161→          }${contextMessage}\nAttempt: ${
162→            (config.transcriptionRetries ?? 1) - effectiveRetries + 1
163→          }\n--- RAW TRANSCRIPT ---\n${fullTranscript}`
164→        );
165→        chunk.failedTranscriptPath = failedPath;
166→        logger.debug(
167→          `[Chunk ${chunk.partNumber}] Saved failed transcript to ${failedPath}`
168→        );
169→      } catch (saveError: any) {
170→        logger.error(
171→          `[Chunk ${chunk.partNumber}] Failed to save failed transcript: ${
172→            saveError.message || saveError
173→          }`
174→        );
175→      }
176→
177→      if (effectiveRetries > 0) {
178→        logger.info(
179→          `[Chunk ${chunk.partNumber}] Retrying transcription (${effectiveRetries} retries remaining)...`
180→        );
181→        if (uploadedFile && uploadedFile.name) {
182→          try {
183→            await ai.files.delete({ name: uploadedFile.name });
184→          } catch (e) {
185→            /* Ignore delete error on retry */
186→          }
187→          uploadedFile = null;
188→        }
189→        return await transcribeChunk(chunk, config, effectiveRetries - 1);
190→      } else {
191→        logger.error(
192→          `[Chunk ${chunk.partNumber}] Transcription failed validation after all retries.`
193→        );
194→        const existingIssueIndex = issues.findIndex(
195→          (i) =>
196→            i.chunkPart === chunk.partNumber &&
197→            i.message.startsWith("Validation failed:")
198→        );
199→        if (existingIssueIndex !== -1) {
200→          issues[existingIssueIndex].severity = "error";
201→          issues[existingIssueIndex].message = `Failed validation after ${
202→            config.transcriptionRetries ?? 1
203→          } attempts: ${validationResult.message}${contextMessage}`;
204→        } else {
205→          issues.push({
206→            type: "TranscriptionError",
207→            severity: "error",
208→            message: `Failed validation after ${
209→              config.transcriptionRetries ?? 1
210→            } attempts: ${validationResult.message}${contextMessage}`,
211→            chunkPart: chunk.partNumber,
212→          });
213→        }
214→        return { transcript: null, issues };
215→      }
216→    } else {
217→      logger.debug(
218→        `[Chunk ${chunk.partNumber}] Transcription passed validation: ${validationResult.message}`
219→      );
220→      chunk.failedTranscriptPath = undefined;
221→      if (!fullTranscript || fullTranscript.trim().length < 10) {
222→        logger.warn(
223→          `[Chunk ${chunk.partNumber}] Transcription passed validation but seems empty or very short.`
224→        );
225→        issues.push({
226→          type: "TranscriptionError",
227→          severity: "warning",
228→          message:
229→            "Transcription passed validation but result is empty or unexpectedly short.",
230→          chunkPart: chunk.partNumber,
231→        });
232→      }
233→      return { transcript: fullTranscript, issues };
234→    }
235→  } catch (error: any) {
236→    const attemptNum =
237→      (config.transcriptionRetries ?? 1) - effectiveRetries + 1;
238→    logger.error(
239→      `[Chunk ${
240→        chunk.partNumber
241→      }] API error during transcription (Attempt ${attemptNum}): ${
242→        error.message || error
243→      }`
244→    );
245→    issues.push({
246→      type: "TranscriptionError",
247→      severity: "error",
248→      message: `API error during attempt ${attemptNum}: ${
249→        error.message || error
250→      }`,
251→      chunkPart: chunk.partNumber,
252→      context: error.stack,
253→    });
254→    return { transcript: null, issues };
255→  } finally {
256→    if (uploadedFile && uploadedFile.name) {
257→      try {
258→        logger.debug(
259→          `[Chunk ${chunk.partNumber}] Deleting uploaded file: ${uploadedFile.uri}`
260→        );
261→        await ai.files.delete({ name: uploadedFile.name });
262→      } catch (deleteError: any) {
263→        logger.warn(
264→          `[Chunk ${chunk.partNumber}] Failed to delete uploaded file ${
265→            uploadedFile.name
266→          } (${uploadedFile.uri}): ${deleteError.message || deleteError}`
267→        );
268→      }
269→    }
270→  }
271→}
