  1→import { Anthropic } from "@anthropic-ai/sdk";
  2→import type { Config, ChunkInfo } from "../types.js";
  3→import * as logger from "../utils/logger.js";
  4→
  5→/**
  6→ * Result structure for Claude calls, including tokens.
  7→ */
  8→export interface ClaudeCallResult {
  9→  responseText: string | null;
 10→  inputTokens?: number;
 11→  outputTokens?: number;
 12→}
 13→
 14→/**
 15→ * Sends a prompt to a Claude model using streaming and returns the text response and token counts.
 16→ *
 17→ * @param prompt The complete prompt string.
 18→ * @param config Pipeline configuration (for API key and model name).
 19→ * @param chunk The current chunk (for logging context).
 20→ * @returns A promise resolving to a ClaudeCallResult object or null if a fatal error occurs.
 21→ */
 22→export async function callClaude(
 23→  prompt: string,
 24→  config: Config,
 25→  chunk: ChunkInfo
 26→): Promise<ClaudeCallResult | null> {
 27→  const apiKey = config.apiKeys.anthropic;
 28→  if (!apiKey) {
 29→    logger.error(`[Chunk ${chunk.partNumber}] Missing Anthropic API key.`);
 30→    return null;
 31→  }
 32→
 33→  const modelName = config.translationModel;
 34→  logger.info(
 35→    `[Chunk ${chunk.partNumber}] Calling Claude model (stream): ${modelName}...`
 36→  );
 37→
 38→  let responseText = "";
 39→  let inputTokens: number | undefined = undefined;
 40→  let outputTokens: number | undefined = undefined;
 41→
 42→  try {
 43→    const client = new Anthropic({ apiKey });
 44→
 45→    const stream = client.messages.stream({
 46→      model: modelName,
 47→      max_tokens: 64000, // Increased from typical 4096 to allow longer outputs
 48→      messages: [
 49→        {
 50→          role: "user",
 51→          content: prompt,
 52→        },
 53→      ],
 54→      thinking: {
 55→        type: "enabled",
 56→        budget_tokens: 10000, // Increased thinking budget
 57→      },
 58→      // Beta features like 'thinking' might not be available/needed for the standard stream,
 59→      // omit them unless specifically required and tested with the stream endpoint.
 60→    });
 61→
 62→    // Listen for text delta events to build the response
 63→    stream.on("text", (textDelta) => {
 64→      responseText += textDelta;
 65→      // Optional: Indicate progress (e.g., logger.debug incremental length)
 66→    });
 67→
 68→    // Remove intermediate token listeners
 69→    // stream.on('messageStart', (message) => { /* ... */ });
 70→    // stream.on('messageStop', (message) => { /* ... */ });
 71→
 72→    stream.on("error", (error) => {
 73→      logger.error(
 74→        `[Chunk ${chunk.partNumber}] Claude stream error event: ${
 75→          error.message || error
 76→        }`
 77→      );
 78→      // This might trigger the outer catch block anyway
 79→    });
 80→
 81→    // Wait for the stream to complete and get the final message object
 82→    const finalMessage = await stream.finalMessage();
 83→
 84→    // Extract final token counts from finalMessage.usage
 85→    if (finalMessage.usage) {
 86→      if (finalMessage.usage.input_tokens)
 87→        inputTokens = finalMessage.usage.input_tokens;
 88→      if (finalMessage.usage.output_tokens)
 89→        outputTokens = finalMessage.usage.output_tokens;
 90→      logger.debug(
 91→        `[Chunk ${chunk.partNumber}] Claude Final Tokens - Input: ${inputTokens}, Output: ${outputTokens}`
 92→      );
 93→    }
 94→
 95→    if (!responseText || responseText.trim().length === 0) {
 96→      logger.warn(
 97→        `[Chunk ${chunk.partNumber}] Claude stream response was empty.`
 98→      );
 99→      // Return empty response but potentially with token counts
100→      return { responseText: null, inputTokens, outputTokens };
101→    }
102→
103→    logger.debug(
104→      `[Chunk ${chunk.partNumber}] Received Claude stream response (Length: ${responseText.length}).`
105→    );
106→    return { responseText, inputTokens, outputTokens };
107→  } catch (error: any) {
108→    logger.error(
109→      `[Chunk ${
110→        chunk.partNumber
111→      }] Claude API error during stream setup or finalization: ${
112→        error.message || error
113→      }`
114→    );
115→    if (error.error?.message) {
116→      logger.error(
117→        `[Chunk ${chunk.partNumber}] Claude API Error Details: ${JSON.stringify(
118→          error.error
119→        )}`
120→      );
121→    }
122→    return null; // Indicate fatal error
123→  }
124→}
