  1→import chalk from "chalk";
  2→import {
  3→  type ParsedTranslationEntry,
  4→  type ProcessingIssue,
  5→  type ParsingIssueType,
  6→} from "../types.js";
  7→import * as logger from "../utils/logger.js";
  8→
  9→// --- Constants ---
 10→const CONTEXT_SNIPPET_LENGTH = 150;
 11→const MM_SS_REGEX = /^(\d{1,2}):(\d{2})$/;
 12→const HH_MM_SS_REGEX = /^(\d{1,2}):(\d{2}):(\d{2})$/;
 13→
 14→// --- Result Interface for Internal Use ---
 15→interface InternalParseResult {
 16→  entries: ParsedTranslationEntry[];
 17→  issues: ProcessingIssue[];
 18→  summary: {
 19→    // Keep summary for potential internal logging or reporting
 20→    totalEntriesAttempted: number;
 21→    successfullyParsed: number;
 22→    markdownBlocksProcessed: number;
 23→    directTagsProcessed: number;
 24→    errors: number;
 25→    warnings: number;
 26→  };
 27→}
 28→
 29→// --- Utility Functions (Adapted) ---
 30→
 31→/** Calculates approximate line number based on character index */
 32→function getLineNumber(content: string, index: number): number {
 33→  const validIndex = Math.max(0, Math.min(index, content.length));
 34→  return content.substring(0, validIndex).split("\n").length;
 35→}
 36→
 37→/** Adds a parsing issue to the provided list. */
 38→function addIssue(
 39→  issuesList: ProcessingIssue[],
 40→  issueDetails: Omit<ProcessingIssue, "lineNumber" | "context" | "type"> & {
 41→    type: ParsingIssueType;
 42→    contextSnippet?: string;
 43→  },
 44→  charIndex?: number,
 45→  fullContent?: string
 46→) {
 47→  const context = issueDetails.contextSnippet
 48→    ? issueDetails.contextSnippet.substring(0, CONTEXT_SNIPPET_LENGTH) +
 49→      (issueDetails.contextSnippet.length > CONTEXT_SNIPPET_LENGTH ? "..." : "")
 50→    : charIndex !== undefined && fullContent
 51→    ? fullContent.substring(charIndex, charIndex + CONTEXT_SNIPPET_LENGTH) +
 52→      (fullContent.length > charIndex + CONTEXT_SNIPPET_LENGTH ? "..." : "")
 53→    : undefined;
 54→
 55→  const fullIssue: ProcessingIssue = {
 56→    ...issueDetails,
 57→    lineNumber:
 58→      charIndex !== undefined && fullContent
 59→        ? getLineNumber(fullContent, charIndex)
 60→        : undefined,
 61→    context: context,
 62→  };
 63→  issuesList.push(fullIssue);
 64→  // No console logging here, handled by caller if needed
 65→}
 66→
 67→// --- Timing Parsers (Adapted from original) ---
 68→function timeToSeconds(time: string): number {
 69→  const timeStr = time.replace(",", ".");
 70→  const parts = timeStr.split(":");
 71→  if (parts.length !== 3) throw new Error(`Invalid time format: "${time}"`);
 72→  const hours = parseInt(parts[0], 10);
 73→  const minutes = parseInt(parts[1], 10);
 74→  const secondsWithMs = parseFloat(parts[2]);
 75→  if (
 76→    isNaN(hours) ||
 77→    isNaN(minutes) ||
 78→    isNaN(secondsWithMs) ||
 79→    hours < 0 ||
 80→    minutes < 0 ||
 81→    minutes > 59 ||
 82→    secondsWithMs < 0 ||
 83→    secondsWithMs >= 60
 84→  ) {
 85→    throw new Error(`Invalid time components in "${time}"`);
 86→  }
 87→  return hours * 3600 + minutes * 60 + secondsWithMs;
 88→}
 89→
 90→function parseMmSs(time: string): number {
 91→  const match = time.match(MM_SS_REGEX);
 92→  if (!match) throw new Error(`Invalid time format: "${time}"`);
 93→  const minutes = parseInt(match[1], 10);
 94→  const seconds = parseInt(match[2], 10);
 95→  if (
 96→    isNaN(minutes) ||
 97→    isNaN(seconds) ||
 98→    minutes < 0 ||
 99→    seconds < 0 ||
100→    seconds > 59
101→  ) {
102→    throw new Error(`Invalid time components in "${time}"`);
103→  }
104→  return minutes * 60 + seconds;
105→}
106→
107→function parseHhMmSs(time: string): number {
108→  const match = time.match(HH_MM_SS_REGEX);
109→  if (!match) throw new Error(`Invalid time format: "${time}"`);
110→  const hours = parseInt(match[1], 10);
111→  const minutes = parseInt(match[2], 10);
112→  const seconds = parseInt(match[3], 10);
113→  if (
114→    isNaN(hours) ||
115→    isNaN(minutes) ||
116→    isNaN(seconds) ||
117→    hours < 0 ||
118→    minutes < 0 ||
119→    minutes > 59 ||
120→    seconds < 0 ||
121→    seconds > 59
122→  ) {
123→    throw new Error(`Invalid time components in "${time}"`);
124→  }
125→  return hours * 3600 + minutes * 60 + seconds;
126→}
127→
128→function isValidTiming(start?: number, end?: number): boolean {
129→  return (
130→    start !== undefined &&
131→    end !== undefined &&
132→    !isNaN(start) &&
133→    !isNaN(end) &&
134→    end > start
135→  );
136→}
