  1→import { existsSync } from "fs";
  2→import * as logger from "../utils/logger.js";
  3→import { parseSrtFile } from "../utils/srt_utils.js";
  4→import type {
  5→  ParsedTranslationEntry,
  6→  ProcessingIssue,
  7→  SrtEntry,
  8→  Config,
  9→} from "../types.js";
 10→
 11→// --- Configuration Constants ---
 12→const MAX_ERROR_RATE = 0.1; // Allow max 10% parsing errors relative to reference count (was 5%)
 13→const MIN_COUNT_MATCH_RATE = 0.8; // Require at least 80% of reference subtitles to be parsed (was 90%)
 14→const MIN_ID_COVERAGE_RATE = 0.8; // Require at least 80% of reference IDs to be present (was 90%)
 15→const MAX_TIMING_MISMATCH_RATE = 0.25; // Allow max 25% of entries to have timing issues (was 10%)
 16→const TIMING_DIFF_MARGIN_RATIO = 0.1; // Allow 10% difference relative to SRT duration
 17→const TIMING_DIFF_ABS_MARGIN_S = 0.5; // Allow absolute difference of 0.5 seconds
 18→
 19→interface ValidationResult {
 20→  isValid: boolean; // True only if NO 'error' severity validation issues occurred
 21→  validationIssues: ProcessingIssue[]; // Issues *added* by this function
 22→}
 23→
 24→/**
 25→ * Validates parsed translation entries against criteria and a reference SRT.
 26→ *
 27→ * @param chunkPart The part number for context.
 28→ * @param parsedEntries The array of parsed entries from the parser module.
 29→ * @param parsingIssues The array of issues generated during the parsing stage.
 30→ * @param referenceSrtPath Path to the corresponding reference SRT chunk.
 31→ * @param config Configuration object containing disableTimingValidation flag
 32→ * @param isLastChunk Flag indicating if this is the last chunk
 33→ * @param isFinalAttempt Flag indicating if this is the final attempt
 34→ * @returns A ValidationResult object.
 35→ */
 36→export async function validateTranslations(
 37→  chunkPart: number,
 38→  parsedEntries: ParsedTranslationEntry[],
 39→  parsingIssues: ProcessingIssue[], // Issues from the parsing step
 40→  referenceSrtPath?: string,
 41→  config?: Pick<Config, "disableTimingValidation" | "chunkDuration">, // Keep config for flags/duration
 42→  isLastChunk: boolean = false, // New flag
 43→  isFinalAttempt: boolean = false // New flag
 44→): Promise<ValidationResult> {
 45→  const validationIssues: ProcessingIssue[] = []; // Issues *added* by this function
 46→  let foundError = false; // Track if any validation check fails critically
 47→
 48→  // --- Reference SRT Loading ---
 49→  let referenceSrtEntries: SrtEntry[] | null = null;
 50→  let referenceSrtCount = 0;
 51→  if (referenceSrtPath && existsSync(referenceSrtPath)) {
 52→    referenceSrtEntries = await parseSrtFile(referenceSrtPath);
 53→    if (referenceSrtEntries) {
 54→      referenceSrtCount = referenceSrtEntries.length;
 55→      logger.debug(
 56→        `[Chunk ${chunkPart} Validation] Loaded ${referenceSrtCount} reference SRT entries.`
 57→      );
 58→    } else {
 59→      validationIssues.push({
 60→        type: "ValidationError",
 61→        severity: "warning",
 62→        chunkPart,
 63→        message: `Could not parse reference SRT file: ${referenceSrtPath}`,
 64→      });
 65→    }
 66→  } else {
 67→    validationIssues.push({
 68→      type: "ValidationError",
 69→      severity: "warning",
 70→      chunkPart,
 71→      message: `Reference SRT file not found or path not provided: ${referenceSrtPath}. Some validation checks skipped.`,
 72→    });
 73→  }
 74→
 75→  const parsedCount = parsedEntries.length;
 76→
 77→  // --- Check 1: Parsing Error Rate ---
 78→  const parsingErrorCount = parsingIssues.filter(
 79→    (p) => p.severity === "error"
 80→  ).length;
 81→  const baseCountForErrorRate =
 82→    referenceSrtCount > 0
 83→      ? referenceSrtCount
 84→      : parsedCount > 0
 85→      ? parsedCount
 86→      : 1;
 87→  const errorRate = parsingErrorCount / baseCountForErrorRate;
 88→
 89→  if (errorRate > MAX_ERROR_RATE) {
 90→    foundError = true; // Critical failure
 91→    validationIssues.push({
 92→      type: "ValidationError",
 93→      severity: "error",
 94→      chunkPart,
 95→      message: `High parsing error rate: ${parsingErrorCount}/${baseCountForErrorRate} (${(
 96→        errorRate * 100
 97→      ).toFixed(1)}%) exceeds threshold of ${(MAX_ERROR_RATE * 100).toFixed(
 98→        1
 99→      )}%.`,
100→    });
101→  }
102→
103→  // --- Checks Requiring Reference SRT ---
104→  if (referenceSrtEntries && referenceSrtCount > 0) {
105→    // --- Check 2: Count Match Rate ---
106→    const countMatchRate = parsedCount / referenceSrtCount;
107→    if (countMatchRate < MIN_COUNT_MATCH_RATE) {
108→      foundError = true; // Critical failure
109→      validationIssues.push({
110→        type: "ValidationError",
111→        severity: "error",
112→        chunkPart,
113→        message: `Low subtitle count match: Parsed ${parsedCount} entries, expected ~${referenceSrtCount} (${(
114→          countMatchRate * 100
115→        ).toFixed(1)}% found, required ${(MIN_COUNT_MATCH_RATE * 100).toFixed(
116→          1
117→        )}%).`,
118→      });
119→    }
120→
121→    // --- Check 3: ID Coverage ---
122→    const referenceIds = new Set(
123→      referenceSrtEntries.map((e) => e.id.toString())
124→    );
125→    const parsedIds = new Set(parsedEntries.map((e) => e.originalId));
126→    let missingIds = 0;
127→    const missingIdList: string[] = [];
128→    referenceIds.forEach((refId) => {
129→      if (!parsedIds.has(refId)) {
130→        missingIds++;
131→        if (missingIdList.length < 10) missingIdList.push(refId); // Keep list short
132→      }
133→    });
134→    const idCoverageRate = 1 - missingIds / referenceSrtCount;
135→    if (idCoverageRate < MIN_ID_COVERAGE_RATE) {
136→      foundError = true; // Critical failure
137→      validationIssues.push({
138→        type: "ValidationError",
139→        severity: "error",
140→        chunkPart,
141→        message: `Low ID coverage: Found ${
142→          parsedIds.size
143→        } unique IDs covering only ${(idCoverageRate * 100).toFixed(
144→          1
145→        )}% of ${referenceSrtCount} reference IDs (required ${(
146→          MIN_ID_COVERAGE_RATE * 100
147→        ).toFixed(1)}%). Missing ${missingIds} IDs (e.g., ${missingIdList.join(
148→          ", "
149→        )}${missingIds > 10 ? "..." : ""}).`,
150→      });
151→    }
152→
153→    // --- Check 4: Timing Consistency (Conditional) ---
154→    if (!config?.disableTimingValidation) {
155→      logger.debug(
156→        `[Chunk ${chunkPart} Validation] Running timing consistency check...`
157→      );
158→      let timingMismatches = 0;
159→      let entriesComparedForTiming = 0;
160→      const mismatchList: string[] = [];
161→      let loggedMismatchCount = 0;
162→      const MAX_MISMATCH_LOGS = 15;
163→      const referenceMap = new Map(
164→        referenceSrtEntries.map((e) => [e.id.toString(), e])
165→      );
166→      const FIXED_TIMING_MARGIN_S = 3.0;
167→
168→      parsedEntries.forEach((parsed) => {
169→        if (
170→          parsed.parsedStartTimeSeconds !== undefined &&
171→          parsed.parsedEndTimeSeconds !== undefined
172→        ) {
173→          const refEntry = referenceMap.get(parsed.originalId);
174→          if (refEntry) {
175→            entriesComparedForTiming++;
176→            const refDuration =
177→              refEntry.endTimeSeconds - refEntry.startTimeSeconds;
178→            const parsedDuration =
179→              parsed.parsedEndTimeSeconds - parsed.parsedStartTimeSeconds;
180→            const durationDiff = Math.abs(parsedDuration - refDuration);
181→            const startDiff = Math.abs(
182→              parsed.parsedStartTimeSeconds - refEntry.startTimeSeconds
183→            );
184→
185→            if (
186→              durationDiff > FIXED_TIMING_MARGIN_S ||
187→              startDiff > FIXED_TIMING_MARGIN_S
188→            ) {
189→              timingMismatches++;
190→              const mismatchDetail = `ID ${
191→                parsed.originalId
192→              }: StartDiff=${startDiff.toFixed(
193→                2
194→              )}s, DurDiff=${durationDiff.toFixed(
195→                2
196→              )}s (Margin: ${FIXED_TIMING_MARGIN_S.toFixed(1)}s)`;
197→              if (mismatchList.length < 5) mismatchList.push(mismatchDetail);
198→
199→              if (loggedMismatchCount < MAX_MISMATCH_LOGS) {
200→                logger.debug(
201→                  `[Chunk ${chunkPart} Validation] Timing mismatch detail: ${mismatchDetail} | Parsed: ${parsed.parsedStartTimeSeconds.toFixed(
202→                    3
203→                  )} -> ${parsed.parsedEndTimeSeconds.toFixed(
204→                    3
205→                  )} (${parsedDuration.toFixed(
206→                    2
207→                  )}s) | Ref: ${refEntry.startTimeSeconds.toFixed(
208→                    3
209→                  )} -> ${refEntry.endTimeSeconds.toFixed(
210→                    3
211→                  )} (${refDuration.toFixed(2)}s)`
212→                );
213→                loggedMismatchCount++;
214→              }
215→
216→              validationIssues.push({
217→                type: "ValidationError",
218→                severity: "warning",
219→                chunkPart,
220→                subtitleId: parsed.originalId,
221→                message: `Timing mismatch: ${mismatchDetail}`,
222→              });
223→            }
224→          }
225→        }
226→      });
227→
228→      if (entriesComparedForTiming > 0) {
229→        const mismatchRate = timingMismatches / entriesComparedForTiming;
230→        if (mismatchRate > MAX_TIMING_MISMATCH_RATE) {
231→          // --- Leniency for Last Chunk, Final Attempt ---
232→          const ignoreTimingError = isLastChunk && isFinalAttempt;
233→          if (!ignoreTimingError) {
234→            foundError = true; // Critical failure *unless* it's last chunk/final attempt
235→          }
236→          // --- End Leniency ---
237→
238→          // Log the error regardless, but severity might be overridden by leniency
239→          const severity = ignoreTimingError ? "warning" : "error";
240→          validationIssues.push({
241→            type: "ValidationError",
242→            severity: severity, // Log as error normally, but warning if leniency applied
243→            chunkPart,
244→            message: `High timing mismatch rate: ${timingMismatches}/${entriesComparedForTiming} (${(
245→              mismatchRate * 100
246→            ).toFixed(
247→              1
248→            )}%) entries exceed fixed timing threshold (${FIXED_TIMING_MARGIN_S.toFixed(
249→              1
250→            )}s). Examples: ${mismatchList.join("; ")}${
251→              timingMismatches > 5 ? "..." : ""
252→            }`,
253→          });
254→
255→          // Add specific log message if error was ignored
256→          if (ignoreTimingError) {
257→            logger.warn(
258→              `[Chunk ${chunkPart} Validation] High timing mismatch rate detected, but IGNORING for final validation decision (Last Chunk & Final Attempt).`
259→            );
260→          }
261→        }
262→      } else if (parsedEntries.some((p) => p.originalTiming)) {
263→        validationIssues.push({
264→          type: "ValidationError",
265→          severity: "warning",
266→          chunkPart,
267→          message: `Could not compare timing for any entries (missing parsed times, or missing reference matches).`,
268→        });
269→      }
270→    } else {
271→      logger.debug(
272→        `[Chunk ${chunkPart} Validation] Skipping timing consistency check due to config flag.`
273→      );
274→    }
275→  } // End of checks requiring reference SRT
276→
277→  // --- Final Decision ---
278→  const isValid = !foundError; // isValid is now true if only ignored timing errors occurred
279→  if (isValid) {
280→    if (validationIssues.length > 0) {
281→      // Passed validation, but had warnings
282→      logger.debug(
283→        `[Chunk ${chunkPart} Validation] Passed with warnings. Issues: ${validationIssues
284→          .map((i) => i.type)
285→          .join(", ")}`
286→      );
287→    } else {
288→      // Passed validation clean
289→      logger.debug(`[Chunk ${chunkPart} Validation] All checks passed.`);
290→    }
291→  } else {
292→    // Failed validation due to at least one error
293→    const errorTypes = validationIssues
294→      .filter((i) => i.severity === "error")
295→      .map((i) => i.type)
296→      .join(", ");
297→    logger.warn(
298→      `[Chunk ${chunkPart} Validation] Failed. Critical Error(s): ${errorTypes}. Total Issues: ${validationIssues.length}`
299→    );
300→  }
301→
302→  return { isValid, validationIssues };
303→}
