54→/**
55→ * Formats a single FinalSubtitleEntry into an SRT block string.
56→ *
57→ * @param entry The final subtitle data.
58→ * @param targetLanguage The target language key (e.g., 'Korean').
59→ * @param config Configuration containing color and fallback marking preferences.
60→ * @returns A string representing the SRT block.
61→ */
62→export function formatSrtEntry(
63→  entry: FinalSubtitleEntry,
64→  targetLanguage: string,
65→  config: {
66→    subtitleColorEnglish?: string;
67→    subtitleColorTarget?: string;
68→    markFallbacks?: boolean;
69→  }
70→): string {
71→  const timingString = `${secondsToTimestamp(
72→    entry.startTimeSeconds
73→  )} --> ${secondsToTimestamp(entry.endTimeSeconds)}`;
74→
75→  const formattedText = applyColorsAndFormatText(
76→    entry.translations,
77→    targetLanguage,
