 38→): Promise<{ chunks: ChunkInfo[]; issues: ProcessingIssue[] }> {
 39→  const {
 40→    videoPath,
 41→    srtPath,
 42→    outputDir,
 43→    chunkDuration,
 44→    chunkOverlap,
 45→    chunkFormat,
 46→    maxConcurrent,
 47→    force,
