 13→/**
 14→ * Get the duration of a video file using ffprobe
 15→ * @param videoPath Path to the video file
 16→ * @returns Promise resolving to duration in seconds, or null if error
 17→ */
 18→export async function getVideoDuration(
 19→  videoPath: string
 20→): Promise<number | null> {
 21→  return new Promise((resolve) => {
 22→    const args = [
 23→      "-v",
 24→      "error",
 25→      "-show_entries",
 26→      "format=duration",
 27→      "-of",
 28→      "default=noprint_wrappers=1:nokey=1",
 29→      videoPath,
 30→    ];
 31→
 32→    logger.debug(`Running ffprobe to get duration of ${videoPath}`);
 33→    const ffprobe = spawn("ffprobe", args);
 34→    let output = "";
 35→    let errorOutput = "";
 36→
 37→    ffprobe.stdout.on("data", (data) => {
 38→      output += data.toString();
 39→    });
 40→
 41→    ffprobe.stderr.on("data", (data) => {
 42→      errorOutput += data.toString();
 43→    });
 44→
 45→    ffprobe.on("close", (code) => {
 46→      if (code !== 0) {
 47→        logger.error(`ffprobe exited with code ${code}: ${errorOutput}`);
 48→        resolve(null);
 49→        return;
 50→      }
 51→
 52→      const duration = parseFloat(output.trim());
 53→      if (isNaN(duration)) {
 54→        logger.error(`Could not parse duration from ffprobe output: ${output}`);
 55→        resolve(null);
 56→        return;
 57→      }
 58→
 59→      logger.debug(`Video duration: ${duration} seconds`);
 60→      resolve(duration);
 61→    });
 62→  });
 63→}
 64→
 65→/**
 66→ * Create a media chunk using ffmpeg
 67→ * @param videoPath Source video path
 68→ * @param outputPath Output path for chunk
 69→ * @param startTime Start time in seconds
 70→ * @param endTime End time in seconds
 71→ * @param format Output format ('mp3' or 'mp4')
 72→ * @returns Promise resolving to true if successful, false if error
 73→ */
 74→export async function createMediaChunk(
 75→  videoPath: string,
 76→  outputPath: string,
 77→  startTime: number,
 78→  endTime: number,
 79→  format: "mp3" | "mp4"
 80→): Promise<boolean> {
 81→  return new Promise((resolve) => {
 82→    const duration = endTime - startTime;
 83→    const formattedStart = secondsToTimestamp(startTime).replace(",", ".");
 84→
 85→    // Basic args for both formats
 86→    const args = [
 87→      "-y", // Overwrite output files
 88→      "-i",
 89→      videoPath,
 90→      "-ss",
 91→      formattedStart,
 92→      "-t",
 93→      duration.toString(),
 94→    ];
 95→
 96→    // Format-specific settings
 97→    if (format === "mp3") {
 98→      args.push(
 99→        "-vn", // No video
100→        "-acodec",
101→        "libmp3lame",
102→        "-ar",
103→        "44100",
104→        "-ab",
105→        "192k",
106→        "-f",
107→        "mp3"
108→      );
109→    } else {
110→      args.push(
111→        "-c:v",
112→        "libx264", // Video codec
113→        "-crf",
114→        "28", // Quality (higher number = lower quality)
115→        "-preset",
116→        "fast",
117→        "-vf",
118→        "scale=640:360", // 360p
119→        "-c:a",
120→        "aac",
121→        "-b:a",
122→        "128k"
123→      );
124→    }
125→
126→    // Output path
127→    args.push(outputPath);
128→
129→    logger.debug(
130→      `Running ffmpeg to create ${format} chunk from ${formattedStart} to ${secondsToTimestamp(
131→        endTime
132→      ).replace(",", ".")}`
133→    );
134→    const ffmpeg = spawn("ffmpeg", args);
135→    let errorOutput = "";
136→
137→    ffmpeg.stderr.on("data", (data) => {
138→      // ffmpeg outputs progress info to stderr
139→      const msg = data.toString();
140→      logger.debug(`[ffmpeg stderr] ${msg.trim()}`); // Log ffmpeg stderr at debug level
141→
142→      // Only accumulate actual errors
143→      if (
144→        msg.includes("Error") ||
145→        msg.includes("error") ||
146→        msg.includes("failed") ||
147→        msg.includes("Cannot")
148→      ) {
149→        errorOutput += msg;
150→      }
151→    });
152→
153→    ffmpeg.on("close", (code) => {
154→      if (code !== 0) {
155→        logger.error(
156→          `ffmpeg exited with code ${code} for chunk ${outputPath}. Error: ${errorOutput}`
157→        );
158→        resolve(false);
159→        return;
160→      }
161→
162→      logger.debug(`Successfully created ${format} chunk: ${outputPath}`);
163→      resolve(true);
164→    });
165→  });
166→}
167→
168→/**
169→ * Split a video into chunks based on pre-calculated time ranges.
170→ */
171→export async function splitVideo(
172→  videoPath: string,
173→  outputDir: string,
174→  format: "mp3" | "mp4",
175→  maxConcurrent: number,
176→  timeChunks: TimeChunk[],
177→  config: Pick<Config, "force">
178→): Promise<{ chunks: ChunkInfo[]; issues: ProcessingIssue[] }> {
179→  const issues: ProcessingIssue[] = [];
180→  // No longer calculating chunks here
181→
182→  // --- Start Processing ---
183→  logger.info(
184→    `Processing ${timeChunks.length} specified chunk(s) for splitting...`
185→  );
186→
187→  // --- Progress Bar Setup ---
188→  const startTime = Date.now(); // Record start time
189→  let intervalId: Timer | null = null; // Timer ID
190→  const multibar = new cliProgress.MultiBar(
191→    {
192→      clearOnComplete: false,
193→      hideCursor: true,
194→      // Remove token placeholders, keep elapsed time
195→      format: `${chalk.cyan(
196→        "{bar}"
197→      )} | {percentage}% | {value}/{total} Chunks | ETA: {eta_formatted} | Elapsed: {elapsed}s | ${chalk.gray(
198→        "{task}"
199→      )}`,
200→    },
201→    cliProgress.Presets.shades_classic
202→  );
203→  const progressBar = multibar.create(timeChunks.length, 0, {
204→    task: "Splitting video...",
205→    elapsed: "0.0",
206→  });
207→  logger.setActiveMultibar(multibar);
208→
209→  // Update timer to 100ms (10 times per second)
210→  intervalId = setInterval(() => {
211→    const elapsedSeconds = ((Date.now() - startTime) / 1000).toFixed(1);
212→    progressBar.update({ elapsed: elapsedSeconds });
213→  }, 100); // Update interval to 100ms
214→
215→  // Create ChunkInfo objects *only* for the chunks we are processing
216→  const chunksToProcess: ChunkInfo[] = timeChunks.map((tc: TimeChunk) => {
217→    const mediaChunkPath = join(
218→      outputDir,
219→      `part${tc.partNumber.toString().padStart(2, "0")}.${format}`
220→    );
221→    return {
222→      partNumber: tc.partNumber,
223→      startTimeSeconds: tc.startTimeSeconds,
224→      endTimeSeconds: tc.endTimeSeconds,
225→      mediaChunkPath,
226→      status: "pending", // Initial status for processing
227→    };
228→  });
229→
230→  // --- Refactored Concurrency Control ---
231→  const queue = [...chunksToProcess];
232→  const activePromises: Promise<void>[] = [];
233→  let processedCount = 0;
234→
235→  const startNextSplitTask = () => {
236→    if (queue.length === 0) return;
237→    const chunk = queue.shift();
238→    if (!chunk) return;
239→    const taskPromise = (async () => {
240→      chunk.status = "splitting";
241→      progressBar.update(processedCount, {
242→        task: `Splitting chunk ${chunk.partNumber}...`,
243→      });
244→
245→      // Check if output file already exists and force is not enabled
246→      if (
247→        !config.force &&
248→        chunk.mediaChunkPath &&
249→        existsSync(chunk.mediaChunkPath)
250→      ) {
251→        logger.debug(
252→          `[Chunk ${chunk.partNumber}] Media chunk ${basename(
253→            chunk.mediaChunkPath
254→          )} already exists. Skipping ffmpeg.`
255→        );
256→        chunk.status = "transcribing"; // Mark as ready for next step
257→        // We still count this as "processed" for the progress bar logic below
258→        // Note: We assume if the media chunk exists, the corresponding SRT chunk
259→        // (if applicable) should also exist or be recreated by srt_splitter if needed.
260→      } else {
261→        // --- Run ffmpeg ---
262→        try {
263→          const success = await createMediaChunk(
264→            videoPath,
265→            chunk.mediaChunkPath!,
266→            chunk.startTimeSeconds,
267→            chunk.endTimeSeconds,
268→            format
269→          );
270→          if (success) {
271→            chunk.status = "transcribing";
272→            logger.debug(`Successfully split part ${chunk.partNumber}`);
273→          } else {
274→            chunk.status = "failed";
275→            chunk.error = "Failed to create media chunk via ffmpeg";
276→            issues.push({
277→              type: "SplitError",
278→              severity: "error",
279→              message: `ffmpeg failed for part ${chunk.partNumber}`,
280→              chunkPart: chunk.partNumber,
281→            });
282→            logger.error(`Failed to split part ${chunk.partNumber}`);
283→          }
284→        } catch (err: any) {
285→          chunk.status = "failed";
286→          chunk.error = `Error during chunk creation: ${err.message || err}`;
287→          issues.push({
288→            type: "SplitError",
289→            severity: "error",
290→            message: `Unhandled error creating media chunk for part ${chunk.partNumber}`,
291→            chunkPart: chunk.partNumber,
292→            context: String(err),
293→          });
294→          logger.error(
295→            `Unhandled error splitting part ${chunk.partNumber}: ${err}`
296→          );
297→        }
298→        // --- End ffmpeg ---
299→      }
300→    })();
301→
302→    taskPromise
303→      .catch((error: any) => {
304→        if (chunk) {
305→          chunk.status = "failed";
306→          chunk.error = `Unexpected error during chunk ${
307→            chunk.partNumber
308→          } split processing: ${error.message || error}`;
309→          logger.error(`[Chunk ${chunk.partNumber}] ${chunk.error}`);
310→          issues.push({
311→            type: "SplitError",
312→            severity: "error",
313→            message: chunk.error,
314→            chunkPart: chunk.partNumber,
315→            context: error.stack,
316→          });
