  7→/**
  8→ * Represents a parsed timestamp range from a transcript line.
  9→ */
 10→export interface ParsedTimestamp {
 11→  startTimeSeconds: number;
 12→  endTimeSeconds: number;
 13→  lineNumber: number; // Original line number for context
 14→}
 15→
 16→/**
 17→ * Parses a relative timestamp (mm:ss) to seconds.
 18→ */
 19→function parseMmSs(timeStr: string): number | null {
 20→  const parts = timeStr.split(":");
 21→  if (parts.length !== 2) return null;
 22→  const minutes = parseInt(parts[0], 10);
 23→  const seconds = parseInt(parts[1], 10);
 24→  if (isNaN(minutes) || isNaN(seconds)) return null;
 25→  return minutes * 60 + seconds;
 26→}
