  return entries;
}

// ── Matching ───────────────────────────────────────────────────────────────

function matchToRef(refSubs: Sub[], genSubs: Sub[]): Map<number, Sub> {
  // Map ref index -> nearest gen sub (many ref can match same gen)
  const map = new Map<number, Sub>();
  for (const ref of refSubs) {
    let best: Sub | null = null;
    let bestDist = Infinity;
    for (const gen of genSubs) {
      const dist = Math.abs(gen.start - ref.start);
      if (dist < bestDist) {
        bestDist = dist;
        best = gen;
      }
    }
    if (best && bestDist <= 10) {
      map.set(ref.index, best);
    }
  }
  return map;
}

// ── Display ────────────────────────────────────────────────────────────────

function truncate(s: string, len: number): string {
  return s.length > len ? s.slice(0, len - 1) + "…" : s;
}

// ── Main ───────────────────────────────────────────────────────────────────

const program = new Command();
program
  .name("compare")
  .description("Compare multiple SRT translations against a reference")
  .requiredOption("-r, --ref <path>", "Reference SRT file")
  .option("-s, --srt <label=path...>", "SRT files to compare (repeatable)", (val: string, prev: string[]) => [...prev, val], [])
  .option("--from <seconds>", "Start time filter (seconds)")
  .option("--to <seconds>", "End time filter (seconds)")
  .parse();

const opts = program.opts();

// Parse labeled SRT inputs
interface Source {
  label: string;
  subs: Sub[];
  matched: Map<number, Sub>;
}

const refSubs = parseSrt(opts.ref, false);
const sources: Source[] = [];

for (const arg of opts.srt) {
  let label: string;
  let path: string;
  if (arg.includes("=")) {
    [label, path] = arg.split("=", 2);
  } else {
    path = arg;
    label = basename(path, ".srt").replace(".bilingual", "");
  }
  const subs = parseSrt(path, true);
  const matched = matchToRef(refSubs, subs);
  sources.push({ label, subs, matched });
}

// Filter by time range
const fromTime = opts.from ? parseFloat(opts.from) : 0;
const toTime = opts.to ? parseFloat(opts.to) : Infinity;
const filteredRef = refSubs.filter((s) => s.start >= fromTime && s.start <= toTime);

// Column widths
const COL = 50;
const labels = sources.map((s) => s.label);
const headerLabels = ["REF", ...labels];

// Print header
console.log();
console.log("  " + "Time".padEnd(8) + headerLabels.map((l) => l.padEnd(COL)).join("│ "));
console.log("  " + "─".repeat(8) + headerLabels.map(() => "─".repeat(COL)).join("┼─"));

for (const ref of filteredRef) {
  const time = shortTs(ref.start);
  const refText = truncate(ref.text, COL - 1);

  const cols = sources.map((src) => {
    const gen = src.matched.get(ref.index);
    if (!gen) return "(no match)".padEnd(COL);
    return truncate(gen.text, COL - 1).padEnd(COL);
  });

  console.log("  " + time.padEnd(8) + refText.padEnd(COL) + "│ " + cols.join("│ "));
}

// Summary
console.log("  " + "─".repeat(8) + headerLabels.map(() => "─".repeat(COL)).join("┼─"));
console.log();
console.log(`  Reference: ${filteredRef.length} subs`);
for (const src of sources) {
  const matched = filteredRef.filter((r) => src.matched.has(r.index)).length;
  console.log(`  ${src.label}: ${src.subs.length} total subs, ${matched}/${filteredRef.length} matched`);
}

