#!/usr/bin/env bun
/**
 * For each chunk, pick 10 random reference subs, show all context levels'
 * translations, and use Claude to rank which best matches the reference.
 * Outputs per-chunk JSON verdicts, then tallies the final result.
 *
 * Usage:
 *   bun scripts/compare_context/rank_samples.ts
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
import { join } from "path";
import Anthropic from "@anthropic-ai/sdk";

// ── Config ─────────────────────────────────────────────────────────────────

const DATA_DIR = join(import.meta.dir, "..", "..", "data");
const VIDEO_NAME = "AnimePahe_Tamayura_-_Sotsugyou_Shashin_Part_3_-_Akogare_-_01_BD_720p_Nishi-Taku";
const CHUNKED_BASE = join(DATA_DIR, "output", `${VIDEO_NAME}_chunked`);
const SWEEP_BASE = join(DATA_DIR, "output", "context_sweep");
const REF_SRT = join(DATA_DIR, "tamayura-sotsugyou-shashin-part3-akogare-ep1-english.srt");
const OUT_DIR = join(DATA_DIR, "output", "context_sweep", "rankings");

const CHUNK_OFFSETS = [0, 314.8, 627.0, 936.6, 1250.5, 1562.0, 1871.4, 2186.3, 2497.9, 2806.2, 3116.7];
const SAMPLES_PER_CHUNK = 10;

// 25% window boundaries: 4 windows
const P25_BOUNDS = [0, 779.175, 1558.35, 2337.525, 3116.7];
const P25_FILES = [
  "25pct_part1of4.bilingual.srt", "25pct_part2of4.bilingual.srt",
  "25pct_part3of4.bilingual.srt", "25pct_part4of4.bilingual.srt"
];
// 50% window boundaries: 2 windows
const P50_BOUNDS = [0, 1558.35, 3116.7];
const P50_FILES = ["50pct_part1of2.bilingual.srt", "50pct_part2of2.bilingual.srt"];

// ── SRT parsing ────────────────────────────────────────────────────────────

interface Sub { index: number; start: number; end: number; text: string; }

function tsToSecs(ts: string): number {
  const [h, m, rest] = ts.split(":");
  const [s, ms] = rest.split(",");
  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
}

function parseSrt(path: string, englishOnly: boolean): Sub[] {
  if (!existsSync(path)) return [];
  let text = readFileSync(path, "utf-8");
  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
  const blocks = text.trim().split(/\n\n+/);
  const entries: Sub[] = [];
  for (const block of blocks) {
    const lines = block.trim().split("\n");
    if (lines.length < 2) continue;
    const index = parseInt(lines[0].trim());
    if (isNaN(index)) continue;
    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
    if (!m) continue;
    const textLines = lines.slice(2);
    let body: string;
    if (englishOnly) {
      body = textLines.map(l => l.replace(/<\/?font[^>]*>/gi, "").replace(/<\/?i>/gi, "").trim())
        .filter(l => l.length > 0)[0] || "";
    } else {
      body = textLines.map(l => l.replace(/<\/?[^>]+>/g, "").trim()).filter(l => l.length > 0).join(" ");
    }
    entries.push({ index, start: tsToSecs(m[1]), end: tsToSecs(m[2]), text: body });
  }
  return entries;
}

function findNearest(subs: Sub[], targetStart: number): Sub | null {
  let best: Sub | null = null;
  let bestDist = Infinity;
  for (const s of subs) {
    const d = Math.abs(s.start - targetStart);
    if (d < bestDist) { bestDist = d; best = s; }
  }
  return best && bestDist <= 10 ? best : null;
}

// ── Pick which 25%/50% file covers a given time ───────────────────────────

function get25File(absTime: number): string {
  for (let i = 0; i < 4; i++) {
    if (absTime >= P25_BOUNDS[i] && absTime < P25_BOUNDS[i + 1])
      return join(SWEEP_BASE, "25pct", P25_FILES[i]);
  }
  return join(SWEEP_BASE, "25pct", P25_FILES[3]);
}

function get50File(absTime: number): string {
  return absTime < P50_BOUNDS[1]
    ? join(SWEEP_BASE, "50pct", P50_FILES[0])
    : join(SWEEP_BASE, "50pct", P50_FILES[1]);
}

// ── Random sampling ────────────────────────────────────────────────────────

function sampleN<T>(arr: T[], n: number): T[] {
  const shuffled = [...arr].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, n);
}

// ── Build samples for a chunk ──────────────────────────────────────────────

interface Sample {
  refText: string;
  refStart: number;
  translations: Record<string, string>; // "10%" -> text, "25%" -> text, etc.
}

function buildChunkSamples(chunkIdx: number): Sample[] {
  const chunkId = `chunk${String(chunkIdx + 1).padStart(2, "0")}`;
  const chunkStart = CHUNK_OFFSETS[chunkIdx];
  const chunkEnd = CHUNK_OFFSETS[chunkIdx + 1];

  // Reference subs in this chunk's time range
  const allRef = parseSrt(REF_SRT, false);
  const chunkRef = allRef.filter(s => s.start >= chunkStart && s.start < chunkEnd);
  if (chunkRef.length === 0) return [];

  // 10% subs (relative timestamps — add chunk offset for matching)
  const raw10 = parseSrt(join(CHUNKED_BASE, chunkId, "no_srt", "video.bilingual.korean.srt"), true);
  const subs10 = raw10.map(s => ({ ...s, start: s.start + chunkStart, end: s.end + chunkStart }));

  // 25%, 50%, 100% (absolute timestamps)
  // Cache parsed files to avoid re-parsing
  const fileCache = new Map<string, Sub[]>();
  function getSubs(path: string): Sub[] {
    if (!fileCache.has(path)) fileCache.set(path, parseSrt(path, true));
    return fileCache.get(path)!;
  }

  const subs100 = getSubs(join(SWEEP_BASE, "100pct", "100pct_full.bilingual.srt"));

  const picked = sampleN(chunkRef, Math.min(SAMPLES_PER_CHUNK, chunkRef.length));

  return picked.map(ref => {
    const subs25 = getSubs(get25File(ref.start));
    const subs50 = getSubs(get50File(ref.start));

    const m10 = findNearest(subs10, ref.start);
    const m25 = findNearest(subs25, ref.start);
    const m50 = findNearest(subs50, ref.start);
    const m100 = findNearest(subs100, ref.start);

    return {
      refText: ref.text,
      refStart: ref.start,
      translations: {
        "10%": m10?.text || "(no match)",
        "25%": m25?.text || "(no match)",
        "50%": m50?.text || "(no match)",
        "100%": m100?.text || "(no match)",
      },
    };
  });
}

// ── Claude ranking ─────────────────────────────────────────────────────────

interface Ranking {
  refText: string;
  refStart: number;
  winner: string;
  reason: string;
}

async function rankWithClaude(samples: Sample[], chunkNum: number): Promise<Ranking[]> {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) throw new Error("ANTHROPIC_API_KEY not set");

  const client = new Anthropic({ apiKey });

  const lines = samples.map((s, i) => {
    const ts = `${Math.floor(s.refStart / 60)}:${String(Math.floor(s.refStart % 60)).padStart(2, "0")}`;
    return `### Line ${i + 1} (${ts})
**Reference:** "${s.refText}"
- **A (10%):** "${s.translations["10%"]}"
- **B (25%):** "${s.translations["25%"]}"
- **C (50%):** "${s.translations["50%"]}"
- **D (100%):** "${s.translations["100%"]}"`;
  }).join("\n\n");

  const prompt = `You are comparing subtitle translations against a human reference translation.
For each line, pick which translation (A=10%, B=25%, C=50%, D=100%) best matches the reference in meaning, tone, and naturalness. If a translation says "(no match)" or "[SKIP THIS SUBTITLE]", it cannot win.

Respond with ONLY a JSON array, no other text:
[{"line": 1, "winner": "B", "reason": "closest wording"}, ...]

${lines}`;

  console.log(`  Chunk ${chunkNum}: calling Claude...`);
  const response = await client.messages.create({
    model: "claude-sonnet-4-20250514",
    max_tokens: 2000,
    messages: [{ role: "user", content: prompt }],
  });

  const text = response.content[0].type === "text" ? response.content[0].text : "";
  // Extract JSON from response
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  if (!jsonMatch) throw new Error(`Failed to parse Claude response for chunk ${chunkNum}: ${text}`);

  const parsed: { line: number; winner: string; reason: string }[] = JSON.parse(jsonMatch[0]);

  const levelMap: Record<string, string> = { A: "10%", B: "25%", C: "50%", D: "100%" };

  return parsed.map(p => ({
    refText: samples[p.line - 1].refText,
    refStart: samples[p.line - 1].refStart,
    winner: levelMap[p.winner] || p.winner,
    reason: p.reason,
  }));
}

// ── Main ───────────────────────────────────────────────────────────────────

mkdirSync(OUT_DIR, { recursive: true });

console.log("=".repeat(60));
console.log("  Context Sweep: Automated Ranking (10 lines x 10 chunks)");
console.log("=".repeat(60));

const allRankings: Ranking[] = [];

for (let c = 0; c < 10; c++) {
  const chunkNum = c + 1;
  const samples = buildChunkSamples(c);
  if (samples.length === 0) {
    console.log(`  Chunk ${chunkNum}: no samples, skipping`);
    continue;
  }

  const rankings = await rankWithClaude(samples, chunkNum);

  // Save per-chunk JSON
  const outPath = join(OUT_DIR, `chunk${String(chunkNum).padStart(2, "0")}_rankings.json`);
  writeFileSync(outPath, JSON.stringify(rankings, null, 2));
  console.log(`  Chunk ${chunkNum}: saved ${rankings.length} rankings -> ${outPath}`);

  allRankings.push(...rankings);
}

// ── Tally ──────────────────────────────────────────────────────────────────

console.log("\n" + "=".repeat(60));
console.log("  FINAL TALLY");
console.log("=".repeat(60));

const tally: Record<string, number> = { "10%": 0, "25%": 0, "50%": 0, "100%": 0 };
for (const r of allRankings) {
  if (tally[r.winner] !== undefined) tally[r.winner]++;
}

const total = allRankings.length;
for (const [level, count] of Object.entries(tally).sort((a, b) => b[1] - a[1])) {
  const pct = ((count / total) * 100).toFixed(1);
  const bar = "█".repeat(Math.round(count / total * 40));
  console.log(`  ${level.padEnd(5)} ${String(count).padStart(3)} / ${total}  (${pct}%)  ${bar}`);
}

// Save combined results
const tallyPath = join(OUT_DIR, "final_tally.json");
writeFileSync(tallyPath, JSON.stringify({ tally, total, rankings: allRankings }, null, 2));
console.log(`\nFull results: ${tallyPath}`);

