#!/usr/bin/env bun
/**
 * Generates per-chunk sample comparison files for agent-based ranking.
 * Outputs: data/output/context_sweep/rankings/chunkNN_samples.txt
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
import { join } from "path";

const DATA_DIR = join(import.meta.dir, "..", "..", "data");
const VIDEO_NAME = "AnimePahe_Tamayura_-_Sotsugyou_Shashin_Part_3_-_Akogare_-_01_BD_720p_Nishi-Taku";
const CHUNKED_BASE = join(DATA_DIR, "output", `${VIDEO_NAME}_chunked`);
const SWEEP_BASE = join(DATA_DIR, "output", "context_sweep");
const REF_SRT = join(DATA_DIR, "tamayura-sotsugyou-shashin-part3-akogare-ep1-english.srt");
const OUT_DIR = join(DATA_DIR, "output", "context_sweep", "rankings");

const CHUNK_OFFSETS = [0, 314.8, 627.0, 936.6, 1250.5, 1562.0, 1871.4, 2186.3, 2497.9, 2806.2, 3116.7];
const P25_BOUNDS = [0, 779.175, 1558.35, 2337.525, 3116.7];
const P25_FILES = ["25pct_part1of4.bilingual.srt", "25pct_part2of4.bilingual.srt", "25pct_part3of4.bilingual.srt", "25pct_part4of4.bilingual.srt"];
const P50_BOUNDS = [0, 1558.35, 3116.7];
const P50_FILES = ["50pct_part1of2.bilingual.srt", "50pct_part2of2.bilingual.srt"];

interface Sub { index: number; start: number; end: number; text: string; }

function tsToSecs(ts: string): number {
  const [h, m, rest] = ts.split(":");
  const [s, ms] = rest.split(",");
  return parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
}

function parseSrt(path: string, englishOnly: boolean): Sub[] {
  if (!existsSync(path)) return [];
  let text = readFileSync(path, "utf-8");
  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
  const blocks = text.trim().split(/\n\n+/);
  const entries: Sub[] = [];
  for (const block of blocks) {
    const lines = block.trim().split("\n");
    if (lines.length < 2) continue;
    const idx = parseInt(lines[0].trim());
    if (isNaN(idx)) continue;
    const m = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
    if (!m) continue;
    const textLines = lines.slice(2);
    let body: string;
    if (englishOnly) {
      body = textLines.map(l => l.replace(/<\/?font[^>]*>/gi, "").replace(/<\/?i>/gi, "").trim()).filter(l => l.length > 0)[0] || "";
    } else {
      body = textLines.map(l => l.replace(/<\/?[^>]+>/g, "").trim()).filter(l => l.length > 0).join(" ");
    }
    entries.push({ index: idx, start: tsToSecs(m[1]), end: tsToSecs(m[2]), text: body });
  }
  return entries;
}

function findNearest(subs: Sub[], t: number): Sub | null {
  let best: Sub | null = null, bestD = Infinity;
  for (const s of subs) { const d = Math.abs(s.start - t); if (d < bestD) { bestD = d; best = s; } }
  return best && bestD <= 10 ? best : null;
}

function get25File(t: number): string {
  for (let i = 0; i < 4; i++) if (t >= P25_BOUNDS[i] && t < P25_BOUNDS[i + 1]) return join(SWEEP_BASE, "25pct", P25_FILES[i]);
  return join(SWEEP_BASE, "25pct", P25_FILES[3]);
}
function get50File(t: number): string {
  return t < P50_BOUNDS[1] ? join(SWEEP_BASE, "50pct", P50_FILES[0]) : join(SWEEP_BASE, "50pct", P50_FILES[1]);
}

mkdirSync(OUT_DIR, { recursive: true });

const allRef = parseSrt(REF_SRT, false);
const subs100 = parseSrt(join(SWEEP_BASE, "100pct", "100pct_full.bilingual.srt"), true);
const fileCache = new Map<string, Sub[]>();
function getCached(p: string): Sub[] { if (!fileCache.has(p)) fileCache.set(p, parseSrt(p, true)); return fileCache.get(p)!; }

for (let c = 0; c < 10; c++) {
  const chunkNum = c + 1;
  const chunkId = `chunk${String(chunkNum).padStart(2, "0")}`;
  const cStart = CHUNK_OFFSETS[c], cEnd = CHUNK_OFFSETS[c + 1];

  const chunkRef = allRef.filter(s => s.start >= cStart && s.start < cEnd);
  const raw10 = parseSrt(join(CHUNKED_BASE, chunkId, "no_srt", "video.bilingual.korean.srt"), true);
  const subs10 = raw10.map(s => ({ ...s, start: s.start + cStart, end: s.end + cStart }));

  // Random 10
  const picked = [...chunkRef].sort(() => Math.random() - 0.5).slice(0, 10);
  picked.sort((a, b) => a.start - b.start);

  let out = `CHUNK ${chunkNum} — Translation Ranking Task\n`;
  out += `For each line, pick which translation (A/B/C/D) best matches the REFERENCE in meaning, tone, and naturalness.\n`;
  out += `If a translation says "(no match)" or "[SKIP THIS SUBTITLE]", it cannot win.\n\n`;

  picked.forEach((ref, i) => {
    const ts = `${Math.floor(ref.start / 60)}:${String(Math.floor(ref.start % 60)).padStart(2, "0")}`;
    const s25 = getCached(get25File(ref.start));
    const s50 = getCached(get50File(ref.start));
    const m10 = findNearest(subs10, ref.start);
    const m25 = findNearest(s25, ref.start);
    const m50 = findNearest(s50, ref.start);
    const m100 = findNearest(subs100, ref.start);

    out += `--- Line ${i + 1} (${ts}) ---\n`;
    out += `REFERENCE: "${ref.text}"\n`;
    out += `A (10%):  "${m10?.text || "(no match)"}"\n`;
    out += `B (25%):  "${m25?.text || "(no match)"}"\n`;
    out += `C (50%):  "${m50?.text || "(no match)"}"\n`;
    out += `D (100%): "${m100?.text || "(no match)"}"\n\n`;
  });

  const outPath = join(OUT_DIR, `${chunkId}_samples.txt`);
  writeFileSync(outPath, out);
  console.log(`${chunkId}: ${picked.length} samples -> ${outPath}`);
}

console.log(`\nDone. Output in ${OUT_DIR}/`);

